gateways.AddEventHandler(controllers.ObjectHandler(func(o controllers.Object) {
	// Avoid expensive reconciles on frequent Gateway status updates (for example, attachedRoutes).
	// The deployment controller only cares about spec/metadata changes.
	if gw, ok := o.(*gateway.Gateway); ok {
		// In practice, status-only updates do not change generation.
		// If generation is unchanged, skip enqueue.
		//
		// Note: even if a status update increments resourceVersion, generation will remain stable.
		// Any spec change (or relevant metadata change) will bump generation and be reconciled.
		//
		// This is best-effort; if a client mutates spec without bumping generation (shouldn't happen),
		// we may skip. Kubernetes guarantees generation bumps on spec changes for built-in types.
		// Gateway is a CRD and follows the same convention.
		prev := dc.gateways.Get(gw.Name, gw.Namespace)
		if prev != nil && prev.Generation == gw.Generation {
			return
		}
	}
	dc.queue.AddObject(o)
}))

