	// Regression test: Gateway status updates (e.g. attachedRoutes) should not trigger a costly reconcile loop.
	// Only spec/metadata changes should enqueue reconciles.

	log.SetOutputLevel(istiolog.DebugLevel)
	writes := make(chan string, 10)
	c := kube.NewFakeClient(&corev1.Namespace{
